public static String newStringIso8859_1(final byte[] bytes) {
    return bytes == null ? null : new String(bytes, Charsets.ISO_8859_1);
}

additional_testcases.testcase:
@Test
public void testNewStringIso8859_1WithEmptyBytes() {
    final byte[] emptyBytes = new byte[0];
    final String result = StringUtils.newStringIso8859_1(emptyBytes);
    Assert.assertNotNull(result);
    Assert.assertEquals("", result);
}

@Test
public void testNewStringIso8859_1WithValidBytes() {
    final byte[] validBytes = {0x48, 0x65, 0x6C, 0x6C, 0x6F};
    final String result = StringUtils.newStringIso8859_1(validBytes);
    Assert.assertNotNull(result);
    Assert.assertEquals("Hello", result);
}

@Test
public void testNewStringIso8859_1WithExtendedCharacters() {
    final byte[] extendedBytes = {(byte)0xE9, (byte)0xE8, (byte)0xE0};
    final String result = StringUtils.newStringIso8859_1(extendedBytes);
    Assert.assertNotNull(result);
    Assert.assertEquals(3, result.length());
    Assert.assertEquals(0xE9, result.charAt(0));
    Assert.assertEquals(0xE8, result.charAt(1));
    Assert.assertEquals(0xE0, result.charAt(2));
}
